      potato_chicken_stew: { name: 'Potato Chicken Stew', texts: { overview: 'A high-restoration meal made from potato and chicken.', game: 'Potato Chicken Stew', codex: 'The potato soaks up the broth, and the chicken looks more dependable.', obtain: ['Beside campfire: Potato + Chicken.'], uses: ['Eat to restore 3 stamina.'], usedIn: [] } },
      potato_beef_stew: { name: 'Potato Beef Stew', texts: { overview: 'A high-restoration meal made from potato and beef.', game: 'Potato Beef Stew', codex: 'A very solid meal. After eating, it feels like adding armor.', obtain: ['Beside campfire: Potato + Beef.'], uses: ['Eat to restore 3 stamina.'], usedIn: [] } },
