      spoiled_milk: { name: 'Spoiled Milk', texts: { overview: 'A failed result from milk in the aging table. Not edible.', game: 'Spoiled Milk', codex: 'It proves time is not every recipe\'s friend.', obtain: ['Aging Table: wait 3 time units with milk inside, 50% chance.'], uses: ['Not edible. No further use yet.'], usedIn: [] } },
      fruit_wine: { name: 'Fruit Wine', texts: { overview: 'The successful fermented result of fruit in the aging table. Eat to restore 2 stamina.', game: 'Fruit Wine', codex: 'Sweetness learned to take the long way around, and gained a stronger finish.', obtain: ['Aging Table: wait 3 time units with fruit inside, 50% chance.'], uses: ['Eat to restore 2 stamina.'], usedIn: [] } },
      rotten_fruit: { name: 'Rotten Fruit', texts: { overview: 'A failed result from fruit in the aging table. Not edible.', game: 'Rotten Fruit', codex: 'It also experienced time, just in the wrong direction.', obtain: ['Aging Table: wait 3 time units with fruit inside, 50% chance.'], uses: ['Not edible. No further use yet.'], usedIn: [] } },
