      hay: { name: 'Hay', texts: { overview: 'Wheat dried by time in the aging table.', game: 'Hay', codex: 'An ingredient can become processed material, perhaps in a single thought.', obtain: ['Aging Table: wait 3 time units with wheat inside.'], uses: ['Craft two hay into a hay nest at the toolbox.'], usedIn: ['Hay Nest'] } },
      hay_nest: { name: 'Hay Nest', texts: { overview: 'A placeable hatching nest. Place an egg on it and wait 3 time units to hatch a chicken.', game: 'Hay Nest', codex: 'It looks like only grass, but eggs find it promising.', obtain: ['Toolbox: Hay + Hay.'], uses: ['Place an egg on it to hatch a chicken.'], usedIn: ['Chicken'] } },
      steamed_bun: { name: 'Steamed Bun', texts: { overview: 'A plain staple baked from basic dough.', game: 'Steamed Bun', codex: 'No filling, but very dependable.', obtain: ['Oven: Dough.'], uses: ['Eat to restore 1 stamina.'], usedIn: [] } },
      meat_bun: { name: 'Meat Bun', texts: { overview: 'A hearty meal made from dough and beef.', game: 'Meat Bun', codex: 'Hiding meat inside is not a secret; it is a surprise.', obtain: ['Oven: Dough + Beef.'], uses: ['Eat to restore 3 stamina.'], usedIn: [] } },
      cake: { name: 'Cake', texts: { overview: 'A sweet dessert meal baked from cake base.', game: 'Cake', codex: 'When cake appears in the wasteland, things feel less wasted.', obtain: ['Oven: Cake Base.'], uses: ['Eat to restore 3 stamina.'], usedIn: [] } },
      original_chicken: { name: 'Original Chicken', texts: { overview: 'Chicken coated in flour and fried on the iron plate.', game: 'Original Chicken', codex: 'The aroma is bold, and so is the name.', obtain: ['Iron Plate: Flour + Chicken.'], uses: ['Eat to restore 3 stamina.', 'Combine with bread to make a chicken burger.'], usedIn: ['Chicken Burger'] } },
      chicken_burger: { name: 'Chicken Burger', texts: { overview: 'Bread with original chicken, currently one of the strongest recovery meals.', game: 'Chicken Burger', codex: 'Between two slices of bread is one complete satisfaction.', obtain: ['Prep Table: Bread + Original Chicken.'], uses: ['Eat to restore 5 stamina.'], usedIn: [] } },
      beef_burger: { name: 'Beef Burger', texts: { overview: 'Bread with steak, currently one of the strongest recovery meals.', game: 'Beef Burger', codex: 'The beef finally found the right context around it.', obtain: ['Prep Table: Bread + Steak.'], uses: ['Eat to restore 5 stamina.'], usedIn: [] } },
